if (! function_exists('weather_alerts')) {
    function weather_alerts($state = null, $zone = null, $event_type = null, $severity = null, $limit = null, $timeout = null)
    {
            $state = $state ?? '';
            $zone = $zone ?? '';
            $event_type = $event_type ?? '';
            $severity = $severity ?? 'minor';
            $limit = $limit ?? 20;
            $timeout = $timeout ?? 15;

            $timeout = max(5, min(30, (int)$timeout));
            $limit = max(1, min(50, (int)$limit));
            $state = strtoupper(trim($state));
            $zone = trim($zone);
            $severity = strtolower(trim($severity));

            if (empty($state) && empty($zone)) {
                return ['success' => false, 'error' => 'Either a two-letter state code or a zone ID is required.'];
            }

            // Severity levels: lower index = MORE severe
            // Example: 'extreme' (0) is more severe than 'moderate' (2)
            $severity_levels = ['extreme', 'severe', 'moderate', 'minor', 'unknown'];
            $min_sev_idx = array_search($severity, $severity_levels);
            if ($min_sev_idx === false) $min_sev_idx = 3; // default: minor

            $fetch_json = function($url, $t) {
                $ctx = stream_context_create([
                    'http' => [
                        'method' => 'GET',
                        'timeout' => $t,
                        'header' => "User-Agent: weather_alerts/1.0\r\nAccept: application/json\r\n",
                        'ignore_errors' => true,
                    ],
                    'ssl' => ['verify_peer' => false, 'verify_peer_name' => false],
                ]);
                $body = @file_get_contents($url, false, $ctx);
                if ($body === false) return ['error' => error_get_last()['message'] ?? 'fetch failed', 'success' => false];
                $status = 200;
                if (isset($http_response_header)) {
                    foreach ($http_response_header as $h) {
                        if (preg_match('#^HTTP/\d+\.\d+ (\d+)#', $h, $m)) { $status = (int)$m[1]; break; }
                    }
                }
                if ($status >= 400) return ['error' => "HTTP $status", 'status' => $status, 'success' => false];
                $data = @json_decode($body, true);
                if ($data === null) return ['error' => 'Invalid JSON', 'success' => false];
                return ['data' => $data, 'status' => $status, 'success' => true];
            };

            $api_url = !empty($zone) 
                ? "https://api.weather.gov/alerts/active/zone/{$zone}"
                : "https://api.weather.gov/alerts/active/area/{$state}";

            $result = $fetch_json($api_url, $timeout);
            if (!$result['success']) {
                return ['success' => false, 'error' => 'NWS API: ' . $result['error']];
            }

            $data = $result['data'];
            $features = $data['features'] ?? [];
            $total = $data['pagination']['total'] ?? count($features);
            $updated = $data['updated'] ?? $data['title'] ?? '';

            $alerts = [];
            foreach ($features as $feature) {
                $props = $feature['properties'] ?? [];
                if (empty($props)) continue;

                $alert_severity = strtolower($props['severity'] ?? 'unknown');
                $sev_idx = array_search($alert_severity, $severity_levels);
                if ($sev_idx === false) $sev_idx = 4;

                // Filter: skip alerts LESS severe than the minimum threshold
                // More severe = lower index. So we skip if sev_idx > min_sev_idx
                if ($sev_idx > $min_sev_idx) continue;

                if (!empty($event_type)) {
                    $event = strtolower($props['event'] ?? '');
                    if (strpos($event, strtolower($event_type)) === false) continue;
                }

                $effective = $props['effective'] ?? '';
                $expires = $props['expires'] ?? '';

                $areas = $props['areaDesc'] ?? '';
                $area_list = !empty($areas) ? array_map('trim', explode(';', $areas)) : [];

                $alerts[] = [
                    'id' => $props['id'] ?? '',
                    'event' => $props['event'] ?? '',
                    'headline' => $props['headline'] ?? '',
                    'severity' => $props['severity'] ?? 'Unknown',
                    'urgency' => $props['urgency'] ?? 'Unknown',
                    'certainty' => $props['certainty'] ?? 'Unknown',
                    'effective' => $effective,
                    'expires' => $expires,
                    'status' => $props['status'] ?? '',
                    'category' => $props['category'] ?? '',
                    'affected_areas' => $area_list,
                    'area_count' => count($area_list),
                    'description' => mb_substr($props['description'] ?? '', 0, 2000),
                    'instruction' => mb_substr($props['instruction'] ?? '', 0, 1000),
                    'sender_name' => $props['senderName'] ?? '',
                ];

                if (count($alerts) >= $limit) break;
            }

            // Sort by severity (most severe first)
            usort($alerts, function($a, $b) use ($severity_levels) {
                $a_idx = array_search(strtolower($a['severity']), $severity_levels);
                $b_idx = array_search(strtolower($b['severity']), $severity_levels);
                if ($a_idx === false) $a_idx = 4;
                if ($b_idx === false) $b_idx = 4;
                return $a_idx - $b_idx;
            });

            $counts = ['Extreme' => 0, 'Severe' => 0, 'Moderate' => 0, 'Minor' => 0, 'Unknown' => 0];
            foreach ($alerts as $a) {
                $s = $a['severity'];
                $counts[$s] = ($counts[$s] ?? 0) + 1;
            }

            return [
                'success' => true,
                'source' => 'National Weather Service API',
                'updated' => $updated,
                'total_available' => $total,
                'alerts_returned' => count($alerts),
                'filters' => [
                    'state_or_zone' => !empty($state) ? $state : $zone,
                    'min_severity' => $severity,
                    'event_type_filter' => $event_type ?: 'none',
                ],
                'summary_by_severity' => $counts,
                'alerts' => $alerts,
            ];
    }
}
